// ── EDIT THESE TWO LINES ───────────────────────────────────────────────
const CRM_API_BASE_URL = 'https://YOUR-CRM-API.example.com'; // public URL of the CRM API
const WEBHOOK_SECRET   = 'CHANGE_ME';                        // must equal N8N_WEBHOOK_SECRET in the CRM .env
// ───────────────────────────────────────────────────────────────────────
// Runs once for ALL items: a single Gmail poll can surface several new messages,
// so iterate over every incoming item rather than only the first item.

function header(item, name) {
  const headers = item.payload?.headers || item.headers || [];
  if (Array.isArray(headers)) {
    const h = headers.find((x) => (x.name || '').toLowerCase() === name.toLowerCase());
    return h?.value || '';
  }
  if (headers && typeof headers === 'object') {
    return headers[name] || headers[name.toLowerCase()] || '';
  }
  return '';
}

const out = [];
for (const entry of $input.all()) {
  const item = entry.json;

  const rawFrom    = item.from || item.From || header(item, 'From') || '';
  const subject    = item.subject || item.Subject || header(item, 'Subject') || item.snippet || '';
  const receivedAt = item.date || item.internalDate || new Date().toISOString();

  // Extract the bare address from "Display Name <user@domain.com>".
  const match = String(rawFrom).match(/<([^>]+)>/);
  const email = (match ? match[1] : String(rawFrom)).trim().toLowerCase();
  if (!email) continue; // no sender address — skip this message

  // Detect opt-out intent (English + Hungarian) from subject + snippet.
  const haystack = `${subject} ${item.snippet || ''}`.toLowerCase();
  const isUnsubscribe = /(unsubscribe|opt[\s-]?out|leiratkoz|\bstop\b)/.test(haystack);

  out.push({
    json: { email, subject, receivedAt, isUnsubscribe, apiBaseUrl: CRM_API_BASE_URL, webhookSecret: WEBHOOK_SECRET },
  });
}

return out;
